import { useState } from "react";
import SpeakBtn from "../SpeakBtn";

export default function VocabSection({ vocab, onDone, done }) {
  const [revealed, setRevealed] = useState({});

  return (
    <div className="fade-in">
      <p className="text-xs text-slate-400 font-bold uppercase tracking-wider mb-4">
        Click the 👁 to reveal Bangla meaning · Click 🔊 to hear pronunciation
      </p>
      <div className="space-y-3">
        {vocab.map((v, i) => (
          <div key={i} className="bg-[#221f35] border border-gray-700 rounded-2xl p-4 hover:border-blue-100 transition-all duration-200">
            <div className="flex items-start gap-3">
              <SpeakBtn text={v.word} />
              <div className="flex-1">
                <div className="flex items-center gap-2 flex-wrap">
                  <span className="text-xl font-extrabold text-gray-200">{v.word}</span>
                  <span className="text-xs text-slate-400 font-mono">{v.phonetic}</span>
                </div>
                <p className="text-sm text-slate-600 mt-0.5">{v.meaning}</p>

                {/* Bangla meaning hidden */}
                <button onClick={() => setRevealed((r) => ({ ...r, [i]: !r[i] }))}
                  className="mt-2 text-xs text-blue-700 font-bold hover:underline flex items-center gap-1">
                  {revealed[i] ? "🙈 Hide Bangla" : "👁 Show Bangla"}
                </button>
                {revealed[i] && (
                  <div className="mt-1.5 text-sm font-bold text-pink-600 bg-pink-50 border border-pink-100 px-3 py-1.5 rounded-lg fade-in">
                    🇧🇩 {v.bangla}
                  </div>
                )}

                {/* Example */}
                <div className="mt-3 flex items-start gap-2">
                  <SpeakBtn text={v.example} size="sm" />
                  <div>
                    <p className="text-sm text-slate-700 italic">"{v.example}"</p>
                    <p className="text-xs text-slate-400 mt-0.5">{v.exampleBn}</p>
                  </div>
                </div>
              </div>
            </div>
          </div>
        ))}
      </div>
      {!done ? (
        <div className="flex justify-end mt-5">
          <button onClick={onDone}
            className="bg-blue-900 hover:bg-blue-800 text-white font-bold px-8 py-3 rounded-xl text-sm transition-all hover:-translate-y-0.5">
            Mark as Done ✓
          </button>
        </div>
      ) : <p className="text-right text-green-700 font-bold text-sm mt-4">✓ Vocabulary completed!</p>}
    </div>
  );
}
